naive.value:
# Round 1: model emits a tool call envelope
curl /v1/responses -d '{
  "model": "qwen3-0.6b",
  "tools": [...],
  "input": "What is the temperature in Paris in Celsius?"
}'
# → {"tool_calls": [{"name": "get_temperature", "arguments": {"city": "Paris"}}]}

# Client runs the tool, then makes a SECOND HTTP call:
curl /v1/responses -d '{
  "model": "qwen3-0.6b",
  "input": [..., {"role":"tool", "name":"get_temperature", "content":"72"}]
}'
# Each tool turn = one extra round-trip.

pie.value:
// Tools run in the inferlet — same WASM, no transport.
#[tool] async fn get_temperature(city: String) -> Result<String> { ... }
#[tool] async fn fahrenheit_to_celsius(f: f64) -> Result<String> { ... }

let mut ctx = Context::new(&model)?;
ctx.system(SYS);
ctx.equip(&[&get_temperature, &fahrenheit_to_celsius])?;
ctx.user(&prompt);

let (_name, args) = decode_tool_call(&mut ctx).await?;
let fahrenheit = get_temperature::call(&args).await?;
ctx.append(&tools::answer_prefix(&model, "get_temperature", &fahrenheit));

let celsius_args = format!(r#"{{\"f\":{fahrenheit}}}"#);
let celsius = fahrenheit_to_celsius::call(&celsius_args).await?;
ctx.append(&tools::answer_prefix(&model, "fahrenheit_to_celsius", &celsius));
Ok(celsius)                              // 22.2, no client RTT
